def _validate(self) -> Settings:
    if self.top_k < 1:
        raise ValueError("TOP_K must be >= 1")
    if self.embedding_dim is not None and self.embedding_dim < 1:
        raise ValueError("EMBEDDING_DIM, when set, must be >= 1")
    if not 0.0 <= self.min_score <= 1.0:
        raise ValueError("MIN_SCORE must be in [0.0, 1.0] (cosine floor)")
    # The fetch-k constraint only matters when rerank is on; gating it keeps
    # raising TOP_K above the default RERANK_FETCH_K from breaking startup
    # for users who never enable reranking.
    if self.rerank_enabled and self.rerank_fetch_k < self.top_k:
        raise ValueError("RERANK_FETCH_K must be >= TOP_K (ranker can only narrow, not widen)")
    if not 0.0 <= self.rerank_min_score <= 1.0:
        raise ValueError("RERANK_MIN_SCORE must be in [0.0, 1.0] (sigmoid floor)")
    return self

# --- grounding-gate helpers ------------------------------------------
# The active grounding floor switches scale when rerank flips on (cosine
# vs sigmoid), so callers that need to skip/override it must consult the
# *active* field, not always MIN_SCORE. Centralising the choice here keeps
# run_query, the acceptance harness, and the live tests in lockstep.

@property
def active_floor(self) -> float:
    """The score floor currently used by :func:`run_query` for abstention."""
    return self.rerank_min_score if self.rerank_enabled else self.min_score

@property
def active_floor_field(self) -> str:
    """Attribute name of the active floor (``"rerank_min_score"`` or ``"min_score"``)."""
    return "rerank_min_score" if self.rerank_enabled else "min_score"

